SELECT AVG(revenue) AS avg_revenue
FROM tickets
WHERE race_id = 1;

SELECT COUNT(*) AS tyre_supplier_count
FROM tyre_suppliers
WHERE tyre_type = 'Soft';

SELECT race_id
FROM fastest_laps
WHERE average_speed > 240;

SELECT position
FROM qualifying
WHERE race_id = 1 AND driver_id = 0;

SELECT AVG(strftime('%s', time)) AS avg_qualifying_time
FROM qualifying
WHERE race_id = 1;

SELECT race_id, SUM(revenue) AS total_revenue, COUNT(DISTINCT merchandise_id) AS item_count
FROM merchandise
GROUP BY race_id;
